import React, { useEffect, useState } from "react";
import axios from "axios";
import { Line, Bar } from "react-chartjs-2";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  Tooltip,
  Legend,
} from "chart.js";

ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  Tooltip,
  Legend
);

export default function Reportes() {
  const [ventasDia, setVentasDia] = useState([]);
  const [ventasMes, setVentasMes] = useState([]);
  const [inicio, setInicio] = useState("");
  const [fin, setFin] = useState("");

  useEffect(() => {
    cargarDatos();
  }, []);

  const cargarDatos = async () => {
    const resDia = await axios.get("http://localhost:5000/api/reportes/ventas/dia");
    const resMes = await axios.get("http://localhost:5000/api/reportes/ventas/mes");
    setVentasDia(resDia.data);
    setVentasMes(resMes.data);
  };

  /* ================= KPI ================= */
  const totalIngresos = ventasDia.reduce((acc, v) => acc + v.TotalIngresos, 0);
  const totalVentas = ventasDia.reduce((acc, v) => acc + v.TotalVentas, 0);
  const promedio = totalVentas ? (totalIngresos / totalVentas).toFixed(2) : 0;

  /* ================= GRÁFICAS ================= */

  const ingresosPorDia = {
    labels: ventasDia.map(v => v.Fecha),
    datasets: [
      {
        label: "Ingresos diarios ($)",
        data: ventasDia.map(v => v.TotalIngresos),
        borderWidth: 3,
        fill: true,
      },
    ],
  };

  const ingresosPorMes = {
    labels: ventasMes.map(v => `${v.Mes}/${v.Año}`),
    datasets: [
      {
        label: "Ingresos mensuales ($)",
        data: ventasMes.map(v => v.TotalIngresos),
      },
    ],
  };

  const ventasPorMes = {
    labels: ventasMes.map(v => `${v.Mes}/${v.Año}`),
    datasets: [
      {
        label: "Cantidad de ventas",
        data: ventasMes.map(v => v.TotalVentas),
      },
    ],
  };

  return (
    <div className="container mt-4">

      {/* KPIs */}
      <div className="row mb-4">
        <div className="col-md-4">
          <div className="card shadow p-3 text-center">
            <h6>Total Ingresos</h6>
            <h4 className="text-success">${totalIngresos.toFixed(2)}</h4>
          </div>
        </div>

        <div className="col-md-4">
          <div className="card shadow p-3 text-center">
            <h6>Total Ventas</h6>
            <h4>{totalVentas}</h4>
          </div>
        </div>

        <div className="col-md-4">
          <div className="card shadow p-3 text-center">
            <h6>Promedio por Venta</h6>
            <h4>${promedio}</h4>
          </div>
        </div>
      </div>

      {/* Gráficas */}
      <div className="card shadow p-4 mb-5">
        <h5>📈 Ingresos por Día</h5>
        <Line data={ingresosPorDia} />
      </div>

      <div className="card shadow p-4 mb-5">
        <h5>📊 Ingresos por Mes</h5>
        <Bar data={ingresosPorMes} />
      </div>

      <div className="card shadow p-4 mb-5">
        <h5>📦 Ventas por Mes</h5>
        <Bar data={ventasPorMes} />
      </div>

    </div>
  );
}
